function uuidv4() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
  });
}
const now = new Date().toISOString();
return $input.all().map(item => ({ json: { ...item.json, post_id: uuidv4(), created_at: now } }));

// Passthrough funnel: receives from ONE of these upstream branches per run:
// - update_stage_researching (pending stage)
// - clear_content_data (researching/rethinking/drafted stages)
// Code node does NOT block waiting for other inputs unlike Merge append mode.
return [{ json: $input.first().json }];

const trigger = $('merge_to_research').first().json;
const post_id = trigger.post_id;
const topic = trigger.topic;
const description = trigger.description || '';

// Read directly from both research nodes
let allItems = [];
try { allItems.push(...$('firecrawl_search').all().map(i => ({...i, _search: 'search1_broad'}))); } catch(e) {}
try { allItems.push(...$('firecrawl_search1').all().map(i => ({...i, _search: 'search2_data'}))); } catch(e) {}
if (allItems.length === 0) {
  allItems = $input.all();
}

let results = [];
const sources = [];
const errors = [];

for (const item of allItems) {
  const d = item.json;
  const searchLabel = item._search || 'web';

  if (d.error) {
    errors.push(typeof d.error === 'object' ? JSON.stringify(d.error) : String(d.error));
    continue;
  }

  // Firecrawl MapSearch: { success: true, data: { web: [], news: [] } }
  if (d.success && d.data && !Array.isArray(d.data) && (d.data.web || d.data.news)) {
    sources.push('firecrawl');
    const webItems = (d.data.web || []).map(r => ({
      source: 'web',
      search: searchLabel,
      url: r.url || '',
      title: r.title || '',
      content: r.description || r.markdown || r.content || ''
    }));
    const newsItems = (d.data.news || []).map(r => ({
      source: 'news',
      search: searchLabel,
      url: r.url || '',
      title: r.title || '',
      content: r.snippet || r.description || r.content || ''
    }));
    results.push(...webItems, ...newsItems);

  // Firecrawl array: { data: [{url, title, markdown}] }
  } else if (d.data && Array.isArray(d.data) && d.data.length > 0) {
    sources.push('firecrawl');
    results.push(...d.data.map(r => ({
      source: 'web',
      search: searchLabel,
      url: r.url || '',
      title: r.title || r.metadata?.title || '',
      content: r.markdown || r.description || r.content || ''
    })));

  // Firecrawl single-item: { url, markdown/title }
  } else if (d.url && (d.markdown !== undefined || d.title) && !d.results && !d.content) {
    sources.push('firecrawl');
    results.push({
      source: 'web',
      search: searchLabel,
      url: d.url || '',
      title: d.title || d.metadata?.title || '',
      content: d.markdown || d.description || ''
    });

  // Tavily wrapped: { results: [{url, title, content}] }
  } else if (d.results && Array.isArray(d.results) && d.results.length > 0) {
    sources.push('tavily');
    results.push(...d.results.map(r => ({
      source: 'tavily',
      search: searchLabel,
      url: r.url || '',
      title: r.title || '',
      content: r.content || r.raw_content || ''
    })));

  // Individual result: { url, content/title }
  } else if (d.url && (d.content || d.raw_content)) {
    const isTavily = d.score !== undefined || d.raw_content !== undefined;
    sources.push(isTavily ? 'tavily' : 'web');
    results.push({
      source: isTavily ? 'tavily' : 'web',
      search: searchLabel,
      url: d.url || '',
      title: d.title || '',
      content: d.content || d.raw_content || ''
    });
  }
}

// Deduplicate by URL
const seen = new Set();
results = results.filter(r => {
  const key = r.url || (r.title + r.content.substring(0, 50));
  if (seen.has(key)) return false;
  seen.add(key);
  return (r.url || r.title || r.content);
});

const uniqueSources = [...new Set(sources)].join('+') || 'none';
if (results.length === 0) {
  throw new Error('No research results from Firecrawl for topic: ' + topic + (errors.length ? '. Errors: ' + errors.join(' | ') : ''));
}

// Summary breakdown for logging
const webCount = results.filter(r => r.source === 'web').length;
const newsCount = results.filter(r => r.source === 'news').length;
const dataCount = results.filter(r => r.search === 'search2_data').length;

const output = {
  post_id,
  topic,
  description,
  source: uniqueSources,
  fetched_at: new Date().toISOString(),
  result_count: results.length,
  result_breakdown: `web:${webCount} news:${newsCount} data/stats:${dataCount}`,
  results
};
if (errors.length > 0) {
  output.source_errors = errors;
}
return [{ json: output }];

const research = $('build_research_json').first().json;
const driveFile = $('save_to_drive').first().json;
const drive_url = 'https://drive.google.com/file/d/' + driveFile.id + '/view';
const folder_id = $('pass_research_data').first().json.folder_id;
const folder_url = 'https://drive.google.com/drive/folders/' + folder_id;
const row = $('merge_to_research').first().json;

// Carry through existing content file IDs (set by clear_content_data on rethinking,
// '' on a fresh pending run). gate_overwrite_v1/v2 will use these to overwrite files.
const content_v1_file_id = row.content_v1_file_id || '';
const content_v2_file_id = row.content_v2_file_id || '';

return [{ json: {
  post_id: research.post_id,
  topic: research.topic,
  description: row.description || '',
  research_drive_url: drive_url,
  post_folder_url: folder_url,
  content_v1_url: '',
  content_v2_url: '',
  content_v1_file_id,
  content_v2_file_id
} }];

// Passthrough funnel: receives from ONE of these upstream branches per run:
// - route_by_stage[2] (researched stage)
// - route_by_stage[3] (content_generating stage)
// - prep_for_content (after full research pipeline)
// - prep_research_skip (after research skip)
// Code node does NOT block waiting for other inputs unlike Merge append mode.
return [{ json: $input.first().json }];

const trigger = $('merge_to_content').first().json;
const url = trigger.research_drive_url || '';
const match = url.match(/\/d\/([a-zA-Z0-9_-]+)/);
const file_id = match ? match[1] : '';
if (!file_id) {
  throw new Error('Could not extract file_id from research_drive_url: ' + url);
}
const folderUrl = trigger.post_folder_url || '';
const folderMatch = folderUrl.match(/\/folders\/([a-zA-Z0-9_-]+)/);
const folder_id = folderMatch ? folderMatch[1] : '';
return [{ json: { post_id: trigger.post_id, topic: trigger.topic, description: trigger.description || '', research_drive_url: url, post_folder_url: folderUrl, file_id, folder_id, content_v1_file_id: trigger.content_v1_file_id || '', content_v2_file_id: trigger.content_v2_file_id || '' } }];

const ctxNode = $('extract_prompts').first().json;
const response = $input.first().json;
let draft = (response.output || response.text || '').trim();

if (!draft) throw new Error('Agent V1 returned empty response. Check Azure OpenAI credentials and connection.');

// Character count check
const charCount = draft.length;
if (charCount < 100) {
  throw new Error(`Agent V1 draft too short (${charCount} chars). Expected 500-1000. Response: ` + draft.substring(0, 200));
}
if (charCount > 1800) {
  // Log warning but do not fail - content is still usable and reviewer can judge
  console.log(`WARN: Agent V1 draft is ${charCount} chars (target 500-1000). Consider shorter prompts.`);
}

return [{ json: {
  post_id: ctxNode.post_id,
  topic: ctxNode.topic,
  research_drive_url: ctxNode.research_drive_url,
  folder_id: ctxNode.folder_id || '',
  prompt_v2: ctxNode.prompt_v2,
  draft_v1: draft,
  draft_v1_chars: charCount,
  content_model: 'gpt-5.3-chat',
  content_v1_file_id: ctxNode.content_v1_file_id || '',
  content_v2_file_id: ctxNode.content_v2_file_id || ''
} }];

const v1Node = $('extract_draft_v1').first().json;
const response = $input.first().json;
let draft = (response.output || response.text || '').trim();

if (!draft) throw new Error('Agent V2 returned empty response. Check Azure OpenAI credentials and connection.');

// Character count check
const charCount = draft.length;
if (charCount < 100) {
  throw new Error(`Agent V2 draft too short (${charCount} chars). Expected 500-1000. Response: ` + draft.substring(0, 200));
}
if (charCount > 1800) {
  console.log(`WARN: Agent V2 draft is ${charCount} chars (target 500-1000). Consider shorter prompts.`);
}

return [{ json: {
  post_id: v1Node.post_id,
  topic: v1Node.topic,
  research_drive_url: v1Node.research_drive_url,
  folder_id: v1Node.folder_id || '',
  draft_v1: v1Node.draft_v1,
  draft_v1_chars: v1Node.draft_v1_chars,
  draft_v2: draft,
  draft_v2_chars: charCount,
  content_model: 'gpt-5.3-chat',
  content_v1_file_id: v1Node.content_v1_file_id || '',
  content_v2_file_id: v1Node.content_v2_file_id || ''
} }];

const item = $('extract_draft_v2').first();
const { post_id, draft_v1, content_v1_file_id, content_v2_file_id } = item.json;
const binaryData = await this.helpers.prepareBinaryData(
  Buffer.from(draft_v1, 'utf-8'),
  'content_variation1.md',
  'text/markdown'
);
return [{ json: { ...item.json, content_v1_file_id: content_v1_file_id || '', content_v2_file_id: content_v2_file_id || '' }, binary: { data: binaryData } }];

const item = $('extract_draft_v2').first();
const { post_id, draft_v2, content_v1_file_id, content_v2_file_id } = item.json;
const binaryData = await this.helpers.prepareBinaryData(
  Buffer.from(draft_v2, 'utf-8'),
  'content_variation2.md',
  'text/markdown'
);
return [{ json: { ...item.json, content_v1_file_id: content_v1_file_id || '', content_v2_file_id: content_v2_file_id || '' }, binary: { data: binaryData } }];

const research = $('build_research_json').first().json;

// On resume from 'researching', post_folder_url may already be in the sheet data.
const existingFolderUrl = $('merge_to_research').first().json.post_folder_url || '';
let folder_id;
if (existingFolderUrl) {
  const m = existingFolderUrl.match(/\/folders\/([a-zA-Z0-9_-]+)/);
  folder_id = m ? m[1] : $('create_post_folder').first().json.id;
} else {
  folder_id = $('create_post_folder').first().json.id;
}

// Thread research_file_id so gate_overwrite_research can use it on rethinking runs.
const research_file_id = $('merge_to_research').first().json.research_file_id || '';

// Ensure description is always present (research.description added in build_research_json)
const description = research.description || $('merge_to_research').first().json.description || '';

return [{ json: { ...research, description, folder_id, research_file_id } }];

const errorItem = $input.first();

// GUARD: only process REAL n8n error envelopes.
// Do NOT use .description â€” that's a field on the LinkedIn post data, not an error flag.
const realError = errorItem.json.error?.message || errorItem.json.message;
if (!realError) {
  // Not a real error envelope â€” data routed here incorrectly, drop silently.
  return [];
}

const errMsg = errorItem.json.error?.message
  || errorItem.json.message
  || JSON.stringify(errorItem.json).substring(0, 300);

// Extract node name from n8n error envelope (multiple possible locations)
const errNode = errorItem.json.error?.node?.name
  || errorItem.json.error?.context?.nodeType
  || (errorItem.json.error?.node?.type || '').split('.').pop()
  || errorItem.json.error?.name
  || 'unknown_node';

const ts = new Date().toISOString();

// Try multiple sources to find post_id
let post_id = errorItem.json.post_id || '';
if (!post_id) { try { post_id = $('merge_to_research').first().json.post_id || ''; } catch(e) {} }
if (!post_id) { try { post_id = $('merge_to_content').first().json.post_id || ''; } catch(e) {} }
if (!post_id) { try { post_id = $('build_research_json').first().json.post_id || ''; } catch(e) {} }
if (!post_id) { try { post_id = $('update_stage_content_gen').first().json.post_id || ''; } catch(e) {} }
if (!post_id) { try { post_id = $('get_file_id').first().json.post_id || ''; } catch(e) {} }
if (!post_id) { try { post_id = $('build_prompts').first().json.post_id || ''; } catch(e) {} }
if (!post_id) { try { post_id = $('extract_draft_v1').first().json.post_id || ''; } catch(e) {} }
// Phase 4 fallbacks
if (!post_id) { try { post_id = $('merge_to_imaging').first().json.post_id || ''; } catch(e) {} }
if (!post_id) { try { post_id = $('build_image_prompts').first().json.post_id || ''; } catch(e) {} }

// Phase 5 fallbacks
if (!post_id) { try { post_id = $('parse_review_decision').first().json.post_id || ''; } catch(e) {} }
if (!post_id) { try { post_id = $('build_review_email').first().json.post_id || ''; } catch(e) {} }
if (!post_id) { try { post_id = $('calc_rewrite_count').first().json.post_id || ''; } catch(e) {} }

if (!post_id) {
  console.log('on_error: no post_id found, error was from node: ' + errNode + ' | ' + errMsg);
  return [];
}

return [{ json: {
  post_id,
  error_log: '[' + ts + '] Node: ' + errNode + ' | Error: ' + errMsg,
  error_node: errNode,
  error_time: ts
} }];

const buildCtx = $('build_prompts').first().json;
const response = $input.first().json;
const agentOutput = (response.output || response.text || '').trim();

if (!agentOutput) {
  throw new Error('prompt_engineer returned empty response. Check Azure OpenAI credentials and connection.');
}

// Extract prompts using delimiters
const v1Match = agentOutput.match(/===PROMPT_V1_START===([\s\S]*?)===PROMPT_V1_END===/);
const v2Match = agentOutput.match(/===PROMPT_V2_START===([\s\S]*?)===PROMPT_V2_END===/);

let prompt_v1 = v1Match ? v1Match[1].trim() : '';
let prompt_v2 = v2Match ? v2Match[1].trim() : '';

// Fallback: split in half
if (!prompt_v1 || !prompt_v2) {
  const lines = agentOutput.split('\n');
  const half = Math.floor(lines.length / 2);
  prompt_v1 = lines.slice(0, half).join('\n').trim() || agentOutput;
  prompt_v2 = lines.slice(half).join('\n').trim() || agentOutput;
}

if (!prompt_v1) throw new Error('Could not extract V1 prompt. Output (first 300): ' + agentOutput.substring(0, 300));
if (!prompt_v2) throw new Error('Could not extract V2 prompt. Output (first 300): ' + agentOutput.substring(0, 300));

// Build enriched agent inputs: prepend topic + description + research context
const researchCtx = buildCtx.research_summary || '';
const contextHeader = `TOPIC: ${buildCtx.topic}
DESCRIPTION: ${buildCtx.description || 'N/A'}
TOTAL RESEARCH RESULTS: ${buildCtx.result_count || 0}

RESEARCH CONTEXT (web + news sources collected for this topic):
${researchCtx}

========================================
YOUR WRITING TASK (from prompt engineer):
========================================`;

const agent_input_v1 = researchCtx
  ? `${contextHeader}\n\n${prompt_v1}`
  : prompt_v1;

const agent_input_v2 = researchCtx
  ? `${contextHeader}\n\n${prompt_v2}`
  : prompt_v2;

return [{ json: {
  post_id: buildCtx.post_id,
  topic: buildCtx.topic,
  description: buildCtx.description || '',
  research_drive_url: buildCtx.research_drive_url,
  folder_id: buildCtx.folder_id || '',
  prompt_v1: agent_input_v1,
  prompt_v2: agent_input_v2,
  content_v1_file_id: buildCtx.content_v1_file_id || '',
  content_v2_file_id: buildCtx.content_v2_file_id || ''
} }];

// Research already exists â€” skip Drive save, but always regenerate content.
// Extract existing file IDs so content gen can overwrite them (no duplicates).
const row = $('merge_to_research').first().json;

function extractFileId(url) {
  const m = (url || '').match(/\/d\/([a-zA-Z0-9_-]+)/);
  return m ? m[1] : '';
}

return [{ json: {
  post_id: row.post_id,
  topic: row.topic,
  description: row.description || '',
  research_drive_url: row.research_drive_url || '',
  post_folder_url: row.post_folder_url || '',
  content_v1_url: '',
  content_v2_url: '',
  content_v1_file_id: extractFileId(row.content_v1_url),
  content_v2_file_id: extractFileId(row.content_v2_url)
} }];

// Re-run: delete old folder (all files inside) and recreate fresh.
// Extract folder ID from post_folder_url so delete_old_folder HTTP node can use it.
// Clear post_folder_url so gate_folder_creation fires TRUE and creates a fresh folder.
// Extract file IDs kept for reference only (no individual file deletes needed).
const row = $input.first().json;

function extractFileId(url) {
  const m = (url || '').match(/\/d\/([a-zA-Z0-9_-]+)/);
  return m ? m[1] : '';
}
function extractFolderId(url) {
  const m = (url || '').match(/\/folders\/([a-zA-Z0-9_-]+)/);
  return m ? m[1] : '';
}

return [{ json: {
  post_id: row.post_id,
  topic: row.topic,
  description: row.description || '',
  user_emails: row.user_emails || '',
  post_folder_id: extractFolderId(row.post_folder_url),
  post_folder_url: '',
  research_drive_url: '',
  content_v1_url: '',
  content_v2_url: '',
  image_v1_url: '',
  image_v2_url: ''
} }];

// HTTP Request DELETE returns empty body (204) on success.
// Restore original row data from clear_content_data so downstream
// nodes have post_id, topic, etc. intact.
return [{ json: $('clear_content_data').first().json }];

// RESUME PATH -- extracts Drive file IDs from sheet URL columns
// Handles BOTH paths:
//   1. route_by_stage (next trigger, full sheet row in $input)
//   2. direct from phase3_end (partial row - only drafted fields in $input)
const row = $input.first().json;

function extractFileId(url) {
  const m = (url || '').match(/\/d\/([a-zA-Z0-9_-]+)/);
  return m ? m[1] : '';
}
function extractFolderId(url) {
  const m = (url || '').match(/\/folders\/([a-zA-Z0-9_-]+)/);
  return m ? m[1] : '';
}

// content URLs -- present in both paths
const content_v1_url = row.content_v1_url || '';
const content_v2_url = row.content_v2_url || '';

// Fields that only come from full sheet row (route_by_stage path).
// When coming directly from phase3_end, fall back to get_file_id which ran in Phase 3.
let post_folder_url = row.post_folder_url || '';
let topic = row.topic || '';
let description = row.description || '';

if (!post_folder_url || !topic) {
  try {
    const ctx = $('get_file_id').first().json;
    post_folder_url = post_folder_url || ctx.post_folder_url || '';
    topic = topic || ctx.topic || '';
    description = description || ctx.description || '';
  } catch(e) {}
}

const v1FileId = extractFileId(content_v1_url);
const v2FileId = extractFileId(content_v2_url);
const folder_id = extractFolderId(post_folder_url);

if (!v1FileId || !v2FileId) {
  throw new Error(
    'Phase 4 resume requires content_v1_url + content_v2_url in the sheet. ' +
    'v1: ' + (content_v1_url || 'empty') + ' | v2: ' + (content_v2_url || 'empty')
  );
}

// user_emails resolution across ALL 4 execution paths:
// Path A: drafted/image_generating direct resume -> row.user_emails (full sheet row in $input)
// Path B: pending fresh run -> $('generate_post_id') ran this execution
// Path C: rethinking -> $('merge_to_research') has it from clear_content_data
// Path D: researched/content_generating resume -> $('merge_to_content') has it from read_all_rows
// Path E: universal fallback -> scan read_all_rows by post_id (always runs at start)
let user_emails = row.user_emails || '';
if (!user_emails) {
  try { user_emails = $('generate_post_id').first().json.user_emails || ''; } catch(e) {}
}
if (!user_emails) {
  try { user_emails = $('merge_to_research').first().json.user_emails || ''; } catch(e) {}
}
if (!user_emails) {
  try { user_emails = $('merge_to_content').first().json.user_emails || ''; } catch(e) {}
}
if (!user_emails) {
  try {
    const pid = row.post_id;
    const matched = $('read_all_rows').all().find(r => r.json.post_id === pid);
    if (matched) user_emails = matched.json.user_emails || '';
  } catch(e) {}
}

return [{ json: {
  post_id:         row.post_id,
  topic,
  description,
  user_emails,
  folder_id,
  post_folder_url,
  content_v1_url,
  content_v2_url,
  v1FileId,
  v2FileId,
  stage: row.stage || ''
} }];

// Read content_variation1.md binary â€” same pattern as build_prompts (getBinaryDataBuffer)
const ctx = $('prep_imaging_resume').first().json;
const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
const draft_v1 = buf.toString('utf-8');
return [{ json: {
  post_id:         ctx.post_id,
  topic:           ctx.topic,
  description:     ctx.description || '',
  user_emails:     ctx.user_emails || '',
  folder_id:       ctx.folder_id,
  post_folder_url: ctx.post_folder_url || '',
  content_v1_url:  ctx.content_v1_url || '',
  content_v2_url:  ctx.content_v2_url || '',
  v2FileId:        ctx.v2FileId,
  stage:           ctx.stage || '',
  draft_v1
} }];

// Read content_variation2.md binary, combine with v1 draft
const ctx = $('read_content_v1').first().json;
const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
const draft_v2 = buf.toString('utf-8');
return [{ json: {
  post_id:         ctx.post_id,
  topic:           ctx.topic,
  description:     ctx.description || '',
  user_emails:     ctx.user_emails || '',
  folder_id:       ctx.folder_id,
  post_folder_url: ctx.post_folder_url || '',
  content_v1_url:  ctx.content_v1_url || '',
  content_v2_url:  ctx.content_v2_url || '',
  draft_v1:        ctx.draft_v1,
  draft_v2,
  stage:           ctx.stage || '',
  image_v1_url:    '',
  image_v2_url:    ''
} }];

// Funnel for Phase 4 â€” receives ONE item from either:
//   prep_for_imaging   (fresh: phase3_end path)
//   read_content_drafts (resume: drafted / image_generating path)
// Code node does NOT block unlike Merge append mode.
return [{ json: $input.first().json }];

// Decode Gemini image response â€” variation 1 (matches content_variation1.md)
const response = $input.first().json;
const parts = response.candidates?.[0]?.content?.parts || [];
const imgPart = parts.find(p => p.inlineData && (p.inlineData.mimeType || '').startsWith('image/'));
if (!imgPart) {
  const txt = parts.filter(p => p.text).map(p => p.text).join('\n');
  throw new Error('No image in Gemini response (v1). Text: ' + txt.substring(0, 400) +
    ' | Parts: ' + JSON.stringify(parts.map(p => Object.keys(p))));
}
const mimeType = imgPart.inlineData.mimeType || 'image/png';
const ext = mimeType.includes('jpeg') ? 'jpg' : 'png';
const ts = new Date().toISOString().replace(/[:.]/g, '-').substring(0, 19);
const filename = 'image_variation1_' + ts + '.' + ext;
const imageBuffer = Buffer.from(imgPart.inlineData.data, 'base64');
const imageBinary = await this.helpers.prepareBinaryData(imageBuffer, filename, mimeType);
const ctx = $('build_image_prompts').first().json;
return [{ json: {
