// Strip AI provenance metadata from JPEG and PNG images
//
// Research basis (2025):
// - LinkedIn "CR" badge reads C2PA content credentials (APP11 JUMBF) only
// - Google Gemini embeds C2PA in APP11 + no EXIF (confirmed from image raw header)
// - Multiple APP11 segments are possible for large C2PA (>64KB); we strip all
//
// JPEG segments removed:
//   APP11 (FF EB) = C2PA JUMBF - Google's signed AI provenance, SynthID action notice
//   APP13 (FF ED) = IPTC-NAA   - structured metadata, may carry AI tool name/copyright
//   APP12 (FF EC) = Picture Info/Ducky - app-specific tags
//   APP14 (FF EE) = Adobe       - Adobe tool marker
//   APP1  (FF E1) = ALL APP1    - covers both XMP and EXIF (neither needed for LinkedIn;
//                                 EXIF is absent in Gemini output; strips any future
//                                 "Software: Google Gemini" EXIF fingerprint)
//   COM   (FF FE) = JPEG comment
//
// JPEG segments kept:
//   APP0  (FF E0) = JFIF header          (required for valid JPEG)
//   APP2  (FF E2) = ICC color profile    (required for correct colors)
//   SOFn, DHT, DQT                       (image structure - required)
//   SOS + all scan data incl. RST        (pixel data - taken verbatim to EOF)
//   EOI   (FF D9)
//
// PNG: keeps IHDR, IDAT, IEND, PLTE only
//
// Note: SynthID watermark is in pixel values - cannot be stripped by metadata removal.
// Removing APP11 is what prevents LinkedIn's "AI-generated" badge (badge reads C2PA only).
// ============================================================

function stripJpegMeta(buf) {
  // All these markers are stripped entirely
  const STRIP = new Set([
    0xEB, // APP11 - C2PA JUMBF (AI provenance, SynthID action notice)
    0xED, // APP13 - IPTC-NAA
    0xEC, // APP12 - Picture Info / Ducky
    0xEE, // APP14 - Adobe marker
    0xE1, // APP1  - all (covers both EXIF and XMP; EXIF absent in Gemini, not needed for LinkedIn)
    0xFE, // COM   - JPEG comment
  ]);

  const STRIP_LABELS = {
    0xEB: 'APP11-C2PA', 0xED: 'APP13-IPTC', 0xEC: 'APP12-Ducky',
    0xEE: 'APP14-Adobe', 0xE1: 'APP1-EXIF/XMP', 0xFE: 'COM',
  };

  if (buf[0] !== 0xFF || buf[1] !== 0xD8) throw new Error('Not a JPEG');

  const parts = [buf.slice(0, 2)]; // SOI FF D8
  const removed = [];
  let i = 2;

  while (i < buf.length - 1) {
    if (buf[i] !== 0xFF) {
      // Non-marker byte outside scan data - take rest verbatim
      parts.push(buf.slice(i));
      break;
    }

    const marker = buf[i + 1];

    // EOI
    if (marker === 0xD9) {
      parts.push(buf.slice(i, i + 2));
      break;
    }

    // SOS: take everything from FF DA to end of file as raw bytes.
    // This handles restart markers (FF D0-D7) inside scan data without any parsing.
    // C2PA / all metadata markers always appear BEFORE SOS in a valid JPEG.
    if (marker === 0xDA) {
      parts.push(buf.slice(i));
      break;
    }

    // RST0-RST7 (FF D0-D7): 2-byte markers, no length field
    if (marker >= 0xD0 && marker <= 0xD7) {
      parts.push(buf.slice(i, i + 2));
      i += 2;
      continue;
    }

    // All other markers: FF XX + 2-byte length (value includes the length bytes)
    if (i + 3 >= buf.length) break;
    const segLen = buf.readUInt16BE(i + 2);
    const segEnd = i + 2 + segLen;

    if (STRIP.has(marker)) {
      const label = STRIP_LABELS[marker] || `APP${marker - 0xE0}`;
      removed.push(`${label}(${segLen}B)`);
    } else {
      parts.push(buf.slice(i, segEnd));
    }

    i = segEnd;
  }

  const clean = Buffer.concat(parts);
  console.log('[strip_meta] JPEG removed:', removed.join(', ') || 'none');
  console.log('[strip_meta] Size:', buf.length, '->', clean.length,
              '(' + (buf.length - clean.length) + ' bytes stripped)');
  return clean;
}

function stripPngMeta(buf) {
  // Keep only pixel-critical PNG chunks; strip tEXt/iTXt/iCCP/XMP/C2PA etc.
  const PNG_SIG = Buffer.from([137, 80, 78, 71, 13, 10, 26, 10]);
  const KEEP = new Set(['IHDR', 'PLTE', 'IDAT', 'IEND']);
  const parts = [PNG_SIG];
  const removed = [];
  let offset = 8;
  while (offset + 12 <= buf.length) {
    const length = buf.readUInt32BE(offset);
    const type   = buf.slice(offset + 4, offset + 8).toString('ascii');
    if (KEEP.has(type)) {
      parts.push(buf.slice(offset, offset + 12 + length));
    } else {
      removed.push(type);
    }
    offset += 12 + length;
  }
  const clean = Buffer.concat(parts);
  console.log('[strip_meta] PNG removed:', removed.join(', ') || 'none');
  console.log('[strip_meta] Size:', buf.length, '->', clean.length);
  return clean;
}

