    cleanBuf = stripPngMeta(srcBuf);
  } else {
    console.log('[strip_meta] Unknown format, skipping');
  }
} catch (e) {
  cleanBuf = srcBuf;
  console.log('[strip_meta] Error, using original:', e.message);
}

const mimeType = imageInput.json.mimeType || 'image/jpeg';
const filename  = imageInput.json.filename;
const cleanBinary = await this.helpers.prepareBinaryData(cleanBuf, filename, mimeType);
return [{ json: imageInput.json, binary: { image: cleanBinary } }];

// Three-tier priority sort:
// 1. Active work rows (researching, drafting, imaging etc) - always first
// 2. review_pending WITH a decision already written (user clicked email) - process ASAP
// 3. review_pending WITHOUT a decision (still waiting for user click) - lowest priority
//
// This ensures:
//   - Active rows never get blocked by review rows
//   - Once a user clicks their review link, their decision is processed next cycle
//   - Rows waiting for a user click sit quietly and don't consume scheduler turns
const items = $input.all();
const activeWork = items.filter(i => (i.json.stage || '').trim() !== 'review_pending');
const rpReady    = items.filter(i => (i.json.stage || '').trim() === 'review_pending' && (i.json.review_decision || '').trim() !== '');
const rpWaiting  = items.filter(i => (i.json.stage || '').trim() === 'review_pending' && (i.json.review_decision || '').trim() === '');
return [...activeWork, ...rpReady, ...rpWaiting];

// Concurrency lock: skip rows currently being processed by another tick.
// Transient stages (researching/content_generating/image_generating) are skipped
// if their updated_at is within the last 8 minutes - meaning another execution
// is still working on them. After 8 min the row is considered stale (crashed
// tick) and becomes pickable again for resume.
const LOCK_MS = 8 * 60 * 1000;
const TRANSIENT = new Set(['researching', 'content_generating', 'image_generating']);
const now = Date.now();

return $input.all().filter(item => {
  const j = item.json;
  const stage = (j.stage || '').toString().toLowerCase().trim();
  if (!TRANSIENT.has(stage)) return true;
  const ts = Date.parse(j.updated_at || '');
  if (isNaN(ts)) return true;            // no timestamp -> allow
  return (now - ts) >= LOCK_MS;          // include only if stale
});

// Final atomic guard before HTTP image gen.
// Aborts if a parallel execution already wrote image_v1_url for this row.
const ctx = $('build_image_prompts').first().json;
const post_id = ctx.post_id;
if (!post_id) throw new Error('lock_check_imaging: missing post_id');

// Pull the latest sheet state if available via update_stage_imaging output
let sheetRow = {};
try { sheetRow = $('update_stage_imaging').first().json || {}; } catch(e) { sheetRow = {}; }

const imgV1 = (sheetRow.image_v1_url || ctx.image_v1_url || '').trim();
const imgV2 = (sheetRow.image_v2_url || ctx.image_v2_url || '').trim();
if (imgV1 || imgV2) {
  throw new Error('lock_check_imaging: image already exists for post_id=' + post_id + ' (v1=' + imgV1 + ', v2=' + imgV2 + '). Parallel execution wrote it. Aborting this branch.');
}

// Pass-through to generate_image_v1 with full extract_image_prompts payload
return [{ json: $input.first().json }];
